arguments.argument:
if global.gamePaused=false
{
  if deathFlail=1
  {
    hspeed=xVel
    vspeed=yVel
  }
  else
  {
    if side=0 //Left (Front)
    {
      x=oMenaceMain.x-4
      y=oMenaceMain.y-6
    }
    else if side=1 //Right (Back)
    {
      x=oMenaceMain.x-26
      y=oMenaceMain.y-12
    }
    image_angle=neutralAngle+bendAngle
  }
  enemyStepEvent()
}
else
{
  hspeed=0
  vspeed=0
}
